// // This module implements a 16-bit shift register with parallel load capability.
// It has a clock input, a reset input, a load input, a 16-bit data input, and a 16-bit output.
// When the reset is asserted, the output should be set to 0.
// When the load input is asserted, the data input should be loaded into the shift register.
// On each clock cycle, if the load input is not asserted, the shift register should shift left by one bit, with the most significant bit (MSB) being filled with a zero.
module shift_register (
    input clk,
    input reset,
    input load,
    input [15:0] data_in,
    output reg [15:0] data_out
);

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            data_out <= 16'b0;
        end else if (load) begin
            data_out <= data_in;
        end else begin
            data_out <= {1'b0, data_out[15:1]};
        end
    end
endmodule

